INSERT INTO S1010_CONSORTIUM (
    MASTER_NO,          ORDER_NO,           COMPANY_NAME,       CEO_NAME,           COM_ADDR,
    COM_HOMEPAGE,       COM_TEL,            COM_HP,             COM_FAX,            BIZ_FIELD,
    BIZ_STAKE
) VALUES (
    #{masterNo},
    (SELECT NVL(MAX(ORDER_NO), 0) + 1 FROM S1010_CONSORTIUM WHERE MASTER_NO = #{masterNo}),
    #{companyName},     #{ceoName},         #{comAddr},         #{comHomepage},     #{comTel},
    #{comHp},           #{comFax},          #{bizField},        #{bizStake}
)

INSERT INTO S1010_CONSORTIUM_HISTORY (
    MASTER_NO,    VERSION,     ORDER_NO,      COMPANY_NAME,   CEO_NAME,
    COM_ADDR,     COM_HOMEPAGE, COM_TEL,      COM_HP,         COM_FAX,
    BIZ_FIELD,    BIZ_STAKE
) VALUES (
    #{masterNo},	#{version},		#{orderNo},	  #{companyName}, #{ceoName},
    #{comAddr},		#{comHomepage}, #{comTel},	  #{comHp},       #{comFax},
    #{bizField},	#{bizStake}
)

mapper.select:
SELECT COALESCE(MAX(v), 0) + 1
FROM (
    SELECT MAX(VERSION) v FROM S1010_HISTORY            WHERE MASTER_NO = #{masterNo}
    UNION ALL
    SELECT MAX(VERSION) v FROM S1010_CONSORTIUM_HISTORY WHERE MASTER_NO = #{masterNo}
)

SELECT DISTINCT version
FROM (
    SELECT VERSION FROM S1010_HISTORY            WHERE MASTER_NO = #{masterNo}
    UNION
    SELECT VERSION FROM S1010_CONSORTIUM_HISTORY WHERE MASTER_NO = #{masterNo}
)
ORDER BY VERSION DESC
